function topologicalSort(graph) {
  const nodes = Object.keys(graph);
  const inDegree = {};
  for (const n of nodes) inDegree[n] = 0;
  for (const n of nodes) {
    for (const dep of graph[n]) {
      if (!(dep in inDegree)) inDegree[dep] = 0;
      inDegree[n]++;
    }
  }
  // Rebuild with all nodes including implicit ones
  const allNodes = Object.keys(inDegree);
  const queue = allNodes.filter(n => inDegree[n] === 0).sort();
  const result = [];
  while (queue.length) {
    queue.sort();
    const n = queue.shift();
    result.push(n);
    for (const dependent of allNodes) {
      if ((graph[dependent] || []).includes(n)) {
        inDegree[dependent]--;
        if (inDegree[dependent] === 0) queue.push(dependent);
      }
    }
  }
  return result.length === allNodes.length ? result : null;
}
